var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"갑주의 무게가 가벼워지는구나.","JPN":"鎧の重さが軽くなっていく。","ENG":"The weight of my armor is lifting.","TWN":"盔甲變輕了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그만큼 이 세계에 타기리온의 영향이 커지고 있다는 의미일 터.","JPN":"それだけこの世界にタギリオンの影響力が大きくなっているということであろう。","ENG":"Which means that Thagirion's influence on this world is getting bigger.","TWN":"這表示塔基里翁在這個世界上的影響力越來越大。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"화근을 찾아내어… 뿌리뽑아야 한다.","JPN":"災いのもとを見つけ出し...…根絶せねばならない。","ENG":"I must find the cause, and... eradicate it.","TWN":"必須尋找禍根……連根拔除。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"뭐…? 너희 코치가 그런 요청을 했다고?","JPN":"何……？　あなたたちのコーチがそんな要請をしたって？","ENG":"What...? Your coach requested that from me?","TWN":"什麼……？是你們教練提出的要求？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"네, 당신이라면 이해해줄 거라던데요?","JPN":"はい、ルネさんなら理解してくれると言いました。","ENG":"Yes. He said you'd understand.","TWN":"對啊。她還說如果是你一定會理解。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"스완의 정식 수배는 그렇다 쳐도 관리도시 여섯 곳이 세워진 이래, 단 한 번도 최고등급 재난경보는 울린 적이 없어.","JPN":"スワンの正式な手配はわかるけど、六つの管理都市ができあがって以来、一度も最高ランクの災難警報を出したことはない。","ENG":"I understand putting an official bounty on Swan, but the highest-level disaster alert has never been triggered since the six Administration Cities were established.","TWN":"先不談史旺的正式通緝令，自從六個管理城市建立以來，從沒有發出過最高級別的災難警報。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이제야 좀 혼란이 수습되나 했는데, 지금 타이밍에 산통을 깨면 어쩌자는 거야?","JPN":"混乱からやっと落ち着いたっていうのに、それをこのタイミングで壊してどうするつもりだ？","ENG":"Just when I thought the chaos was settling down, you want me to cause more confusion?","TWN":"還以為混亂終於要平息了，結果又出事情？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>사람들에게 경각심을 주는 정도로 세계멸망을 막을 수 있다면 해볼만한 거래지 않겠나?</color>","JPN":"<color=#ffd34c>人々に警告するだけで世界の滅亡を防げるのなら、やってみる価値がある取引ではないか？</color>","ENG":"<color=#ffd34c>Won't it be worth it if you can prevent the apocalypse by bringing awareness to the people?</color>","TWN":"<color=#ffd34c>如果能透過引起人們的警戒心來避免世界末日，這難道不值得一試嗎？</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…라고 코치가 그러던데?","JPN":"……とコーチが言っていたぞ？","ENG":"...Is what Coach said.","TWN":"教練是這麼說的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"선택은 어디까지나 시니어인 당신의 몫으로 맡기겠다고 했어.","JPN":"選択はあくまでもシニアであるあんたに任せると言ったよ。","ENG":"He also said that it's up to you, the Senior.","TWN":"他說會把決定權留給身為Senior的你。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하, 책임은 전부 이쪽에 떠넘겨 놓고 선택하라고?","JPN":"は、責任は全部こっちに押し付けておいて、選択しろって？","ENG":"Ugh, so he wants me to take all responsibility and choose?","TWN":"哈，他是想把責任都推卸給我吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"말이 부탁이지 아주 자기 멋대로잖아.","JPN":"何が頼みだ、全部自分勝手じゃないか。","ENG":"Sounds more like a one-sided request if you ask me.","TWN":"這哪是請求，簡直胡來。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"최고등급 재난경보라고요?","JPN":"最高ランクの災難警報？","ENG":"The highest-level disaster alert?","TWN":"最高級別的災難警報？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그래, 상부에선 이미 결정을 마쳤다고 하더군.","JPN":"そう、上層部ではすでに決定を下したようだ。","ENG":"Yes. The higher-ups have already made their decision.","TWN":"是的，據說高層已經做好決定了。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"관리도시 여섯 곳 전체에 경보를 울릴 예정이야.","JPN":"六つの管理都市全体に警報を鳴らす予定だ。","ENG":"An alarm is going to set off at all six Administration Cities.","TWN":"他們將在全部六座管理城市發佈警報。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"그 경보는 세상이 망한다는 신호탄이잖아요! 괜히 시민들 혼란만 가중되는 거 아녜요?","JPN":"その警報は世界が滅ぶというサインでしょ！　市民たちが混乱するだけじゃない！","ENG":"But that's only supposed to be used when the world is ending! Won't it cause more chaos for the people?","TWN":"那可是世界將滅亡的警報！只會加劇市民們的不安！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"내가 알기로, 관리국은 지금까지 한 번도 틀린 결정을 내린 적이 없어.","JPN":"俺が知っている限り、管理局は今まで一度も間違った判断をしたことがない。","ENG":"From what I know, the Administration has never made a wrong decision.","TWN":"但據我所知，管理局從未做出錯誤的決定。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그러니 이번에도 상부를 믿고, 우린 우리 역할에 충실히 임하는 수 밖에.","JPN":"だから今回も上層部を信じて、俺たちは自分の役割を果たすしかない。","ENG":"So, all we can do is trust their decision and do our jobs.","TWN":"所以這次也相信高層，做好我們的本份吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"뭐지? 적의 공습인가?!","JPN":"何だ？　敵襲か！？","ENG":"Huh? Is it another enemy attack?!","TWN":"怎麼回事？敵人的空襲？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L33_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"재난경보네요. 그것도 가장 높은 등급의.","JPN":"災難警報ですね。それも最高ランクの。","ENG":"It's a disaster alert. The highest-level one at that.","TWN":"是災難警報，而且是最高級別的警報。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그럼… 4종 침식체 같은 게 나온 거야?","JPN":"じゃあ……第4種侵食体のようなものが出たの？","ENG":"Then... did something like a Category 4 C.O. appear?","TWN":"難道……出現了4類侵蝕體？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"침식체 몇 마리 차원의 문제가 아니에요.","JPN":"侵食体が現れたレベルではありません。","ENG":"This is a lot bigger than a few C.O.s.","TWN":"這不僅僅是幾個侵蝕體的問題。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"세계의 존망이 걸린 대정화전쟁 같은 일이 또다시 벌어질 수 있다는 뜻이니까요.","JPN":"世界の存亡がかかっている大浄化戦争のようなことがまた起こるという意味です。","ENG":"It means that a world-ending event like the Grand Purification War could happen again.","TWN":"這表示可能會再次爆發像大淨化戰爭一樣攸關世界存亡的事件。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"아마 지금쯤 긴급방송이 나가고 있을 겁니다.","JPN":"たぶん今頃、緊急放送が流れているはずです。","ENG":"There should be an emergency broadcast being aired right now.","TWN":"現在應該正在進行緊急廣播。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리국에서 알립니다.</color>","JPN":"<color=#ffd34c>管理局からお知らせします。</color>","ENG":"<color=#ffd34c>This is the Administration.</color>","TWN":"<color=#ffd34c>管理局通知。</color>"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이것은 실제 상황입니다.</color>","JPN":"<color=#ffd34c>これは訓練ではありません。</color>","ENG":"<color=#ffd34c>This is not a drill.</color>","TWN":"<color=#ffd34c>這不是演習。</color>"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재 눈보라 현상을 동반한 고위 침식파가 전세계를 뒤덮고 있습니다.</color>","JPN":"<color=#ffd34c>現在、吹雪を伴う高位の侵食波が全世界を覆いつくしています。</color>","ENG":"<color=#ffd34c>The high-grade Corruption ray accompanied by the blizzard is currently covering the world.</color>","TWN":"<color=#ffd34c>目前，一股伴有暴風雪的高強度侵蝕波正在席捲全世界。</color>"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시민 여러분께서는 절대 눈보라에 노출되지 마시고, 안전한 실내장소로 대피하여 재난방송을 청취해주시기 바랍니다.</color>","JPN":"<color=#ffd34c>市民の皆様は決して吹雪の中に出ず、室内の安全な場所に退避し、テレビ・ラジオをつけてください。</color>","ENG":"<color=#ffd34c>Citizens are asked to not be exposed to the snow, evacuate to a safe place indoors, and listen to the disaster broadcast.</color>","TWN":"<color=#ffd34c>各位市民千萬不要暴露在暴風雪中，請在室內躲避並收聽災害廣播。</color>"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안내된 지침은 재난경보 해제까지 유효합니다.</color>","JPN":"<color=#ffd34c>ご案内している行動指針は災難警報が解除されるまで有効です。</color>","ENG":"<color=#ffd34c>The broadcast guidelines will remain in effect until the disaster alert is lifted.</color>","TWN":"<color=#ffd34c>持續到警報解除為止。</color>"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 관리국이 해당 현상의 원인을 파악하고 해결 중에 있습니다.</color>","JPN":"<color=#ffd34c>現在、管理局ではこの現象の原因を把握し、解決に向けて動いています。</color>","ENG":"<color=#ffd34c>Currently, the Administration is finding the cause of this phenomenon and working to resolve it.</color>","TWN":"<color=#ffd34c>管理局目前正在努力找出原因要解決這個問題。</color>"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그러니 시민 여러분께선 관리국의 지침에 따라주시길 당부드립니다.</color>","JPN":"<color=#ffd34c>ですので、市民の皆様には管理局の行動指針に従ってくださいますようお願いいたします。</color>","ENG":"<color=#ffd34c>We ask that citizens follow the Administration's guidelines.</color>","TWN":"<color=#ffd34c>請各位市民務必遵循管理局的指示。</color>"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>눈보라에 노출되지 마십시오.</color>","JPN":"<color=#ffd34c>繰り返します、吹雪の中には絶対に出ないでください。</color>","ENG":"<color=#ffd34c>Do not expose yourself to the snow.</color>","TWN":"<color=#ffd34c>請勿暴露在暴風雪中。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>재난방송을 계속해서 청취해주십시오.</color>","JPN":"<color=#ffd34c>テレビ・ラジオをつけてください。</color>","ENG":"<color=#ffd34c>Keep listening to the disaster broadcast.</color>","TWN":"<color=#ffd34c>請繼續收聽災難廣播。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리국에 협조해주십시오.</color>","JPN":"<color=#ffd34c>管理局にご協力をお願いいたします。</color>","ENG":"<color=#ffd34c>Cooperate with the Administration.</color>","TWN":"<color=#ffd34c>請協助管理局的工作。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"}]`);export{e as default};